const body = $input.first().json.body;
if (!body.events || body.events.length === 0) return [];

const EMPLOYEE_MAP = {
  "Uc1e1e958fb952752c3d34628a17585a1": "野添優",
  "Uf662ab811bee1780522da7356c0efb9e": "丸田翔吾",
  "Ua9a65f01bf77adcc825b05811950480d": "源地健史",
  "U65929805c0527b9f75b5276fc250c304": "服部秀一",
  "Uadfb98160637cc7f96bccb051c4a51f9": "梶原通信",
  "REPLACE_IMOTO_USERID":              "井本貴史",
  "REPLACE_LLS_USERID":                "LLS電気",
  "REPLACE_TRUST_USERID":              "株式会社トラストテクノス",
  "REPLACE_RISE_USERID":               "株式会社RISE"
};

const results = [];
for (const event of body.events) {
  if (event.type !== 'message' || event.message.type !== 'text') continue;

  const userId     = event.source.userId;
  const replyToken = event.replyToken;
  const text       = event.message.text.trim();

  const now   = new Date();
  const year  = now.getFullYear();
  const month = now.getMonth() + 1;
  const fileName = `稼働表_${year}年${month}月.xlsx`;

  const extract = (label, str) => {
    const m = str.match(new RegExp(label + '[：:]\\s*(.+)'));
    return m ? m[1].trim() : null;
  };

  if (text.startsWith('請求集計')) {
    const employeeName = EMPLOYEE_MAP[userId] || 'unknown';
    const companyName = extract('会社名', text) || text.replace(/^請求集計[\\s　]*/, '').trim();
    if (!companyName) {
      results.push({ json: { valid: false, replyToken, errorMessage: '会社名を入力してください\n例：\n請求集計\n会社名：梶原通信' } });
      continue;
    }
    results.push({ json: { valid: true, messageType: 'billing_query', replyToken, userId, employeeName, companyName, fileName, year, month } });
    continue;
  }

  if (!text.startsWith('日報')) {
    results.push({ json: { valid: false, replyToken, errorMessage: '「日報」から始めてください' } });
    continue;
  }

  const employeeName = EMPLOYEE_MAP[userId];
  if (!employeeName) {
    results.push({ json: { valid: false, replyToken, errorMessage: 'このアカウントは登録されていません。管理者にお問い合わせください。' } });
    continue;
  }

  results.push({ json: {
    valid: true,
    messageType: 'daily_report',
    replyToken,
    userId,
    employeeName,
    fileName,
    year,
    month,
    messageText: text
  }});
}
return results;

const apiKey = 'YOUR_ANTHROPIC_API_KEY';
const input = $input.first().json;

const companyMap = [
  '平成 → 平成システム', 'トラスト → トラストテクノス', 'オーク → オークコミュニケーション',
  '千里 → 千里スカイハイツ管理組合', '港 → 港振興業', 'コウシン → 港振興業',
  '港振 → 港振興業', '梶原 → 梶原通信'
].join('
');

const prompt = `以下のLINEメッセージは電気工事会社の日報です。全ての現場の情報を抽出してJSON形式で返してください。

メッセージ：
${input.messageText}

【会社名の略称対応】以下の略称は正式名称に変換してください：
${companyMap}
FGE → FGE
mtr → mtr
ライズ → ライズ
菊次 → 菊次
ページ → ページ
G-STYLE → G-STYLE
ジースタイル → G-STYLE
Gスタイル → G-STYLE

【項目の略称対応】以下の略称・表記ゆれを正しく解釈してください：
- 区分：昼・日勤 → 昼勤 / 夜・夜勤 → 夜勤 / 省略時は昼勤
- 開始・終了：「8〜17」「8時から17時」「8:00-17:00」などすべて対応
- 休憩：「休憩60」「休60」など / 省略時は0
- 高速料金：「高速」「高速代」「ETC」など
- 移動距離：「距離」「移動」「km」など
- 駐車場：「駐車」「P」など
- 資材費：「資材」「材料」など
- 日付：「今日」は本日、「4/25」「4月25日」なども対応 / 年省略時は2026年

以下のJSON形式で返してください。現場が複数ある場合はsitesに複数のオブジェクトを入れてください：
{"date":"YYYY/MM/DD","sites":[{"kubun":"昼勤","companyName":"会社名","propertyName":"物件名","startTime":"HH:MM","endTime":"HH:MM","breakMin":0,"workContent":"作業内容","highwayFee":0,"distance":0,"parkingFee":0,"materialFee":0,"personnelNames":null,"personnelCount":null}]}

kubunは 昼勤/夜勤 のいずれか。personnelNames・personnelCountは人員がいなければnull。人員が記載されている場合、名前をスペース・読点・中点（・）などで区切られたリストとして認識し、personnelNamesに「名前1・名前2・名前3」形式で、personnelCountには名前の数を自動でカウントして設定してください。（n名）の記載がなくても名前の数から自動計算してください。JSONのみを返してください。`;

const response = await this.helpers.httpRequest({
  method: 'POST',
  url: 'https://api.anthropic.com/v1/messages',
  headers: {
    'x-api-key': apiKey,
    'anthropic-version': '2023-06-01',
    'content-type': 'application/json'
  },
  body: {
    model: 'claude-haiku-4-5-20251001',
    max_tokens: 1024,
    stream: false,
    messages: [{ role: 'user', content: prompt }]
  },
  json: true
});

return [{ json: { ...input, claudeResponse: response } }];

const combined = $input.first().json;
const data = combined;
const claudeResponse = combined.claudeResponse;

try {
  const textContent = claudeResponse.content[0].text;
  const jsonMatch = textContent.match(/\{[\s\S]*\}/);
  if (!jsonMatch) throw new Error('Claude応答のJSON抽出失敗');

  const parsed = JSON.parse(jsonMatch[0]);
  if (!parsed.date || !parsed.sites || parsed.sites.length === 0) {
    throw new Error('日付または現場情報が取得できませんでした');
  }

  for (const site of parsed.sites) {
    if (site.startTime && site.endTime) {
      const [sh, sm] = site.startTime.split(':').map(Number);
      const [eh, em] = site.endTime.split(':').map(Number);
      let totalMin = (eh * 60 + em) - (sh * 60 + sm);
      if (totalMin < 0) totalMin += 24 * 60;
      totalMin -= (site.breakMin || 0);
      const h = Math.floor(totalMin / 60);
      const m = totalMin % 60;
      site.workingTime = `${h}:${String(m).padStart(2, '0')}`;
    }
    site.highwayFee  = parseInt(site.highwayFee)  || 0;
    site.distance    = parseInt(site.distance)     || 0;
    site.parkingFee  = parseInt(site.parkingFee)   || 0;
    site.materialFee = parseInt(site.materialFee)  || 0;
    site.breakMin    = parseInt(site.breakMin)     || 0;
  }

  const dateParts = parsed.date.split('/');
  const fileYear  = parseInt(dateParts[0]);
  const fileMonth = parseInt(dateParts[1]);
  const fileName  = `稼働表_${fileYear}年${fileMonth}月.xlsx`;

  return [{ json: { ...data, parsedDate: parsed.date, sites: parsed.sites, valid: true, fileName, fileYear, fileMonth } }];

} catch (e) {
  return [{ json: {
    valid: false,
    replyToken: data.replyToken,
    errorMessage: `日報の解析に失敗しました。\n以下を確認してください：\n・日付が正しいか（例：2026/05/01）\n・区分が正しいか（昼勤 / 夜勤）`
  }}];
}

const ExcelJS = require('exceljs');
return await (async () => {
  const data = $input.first().json;
  const downloadUrl = data['@microsoft.graph.downloadUrl'] || data.downloadUrl;
  const fileId = data.id || data.fileId;

  try {
    if (!downloadUrl) throw new Error('ダウンロードURLが取得できませんでした');
    const workbook = new ExcelJS.Workbook();
    const res = await this.helpers.httpRequest({ method: 'GET', url: downloadUrl, encoding: 'arraybuffer', returnFullResponse: false });
    await workbook.xlsx.load(Buffer.from(res), { useSharedStrings: false });

    const MULTI_PERSON = ['梶原通信', 'LLS電気', '株式会社トラストテクノス', '株式会社RISE'];
    const isMulti = MULTI_PERSON.includes(data.employeeName);
    const sheet = workbook.getWorksheet(data.employeeName);
    if (!sheet) throw new Error(`シート「${data.employeeName}」が見つかりません`);

    const normalizeKubun = (k) => {
      if (!k) return '';
      const s = String(k).trim();
      if (s === '昼勤' || s === '昼' || s === '日勤') return '昼勤';
      if (s === '夜勤' || s === '夜') return '夜勤';
      return s;
    };

    const normalizeDate = (val) => {
      if (!val) return '';
      if (typeof val === 'object' && typeof val.getTime === 'function') {
        const d = new Date(val.getTime() + 9 * 3600000);
        return `${d.getUTCFullYear()}/${String(d.getUTCMonth()+1).padStart(2,'0')}/${String(d.getUTCDate()).padStart(2,'0')}`;
      }
      if (typeof val === 'number') {
        const d = new Date(Math.round((val - 25569) * 86400 * 1000) + 9 * 3600000);
        return `${d.getUTCFullYear()}/${String(d.getUTCMonth()+1).padStart(2,'0')}/${String(d.getUTCDate()).padStart(2,'0')}`;
      }
      return String(val).trim();
    };

    const isDuplicate = (targetDate, targetKubun, targetCompany, targetProperty) => {
      let found = false;
      sheet.eachRow((row, num) => {
        if (num < 3 || found) return;
        const rowDate    = normalizeDate(row.getCell(1).value);
        const rowKubun   = normalizeKubun(row.getCell(2).value);
        const rowCompany = String(row.getCell(3).value || '').trim();
        const rowProp    = String(row.getCell(4).value || '').trim();
        if (rowDate === targetDate && rowKubun === targetKubun &&
            rowCompany === targetCompany && rowProp === targetProperty) {
          found = true;
        }
      });
      return found;
    };

    const findNextEmptyRow = () => {
      let lastRow = sheet.lastRow ? sheet.lastRow.number : 2;
      for (let i = 3; i <= lastRow + 1; i++) {
        const row = sheet.getRow(i);
        const cellA = row.getCell(1).value;
        if (!cellA || String(cellA).trim() === '') return row;
      }
      return sheet.getRow(lastRow + 1);
    };

    const duplicates = [];
    let written = false;

    for (const site of data.sites) {
      const kubun   = normalizeKubun(site.kubun);
      const company = site.companyName || '';
      const prop    = site.propertyName || '';

      if (isDuplicate(data.parsedDate, kubun, company, prop)) {
        duplicates.push(`${company}／${prop}`);
        continue;
      }

      const row = findNextEmptyRow();
      const dateCell = row.getCell(1);
      dateCell.value = data.parsedDate || '';
      dateCell.numFmt = '@';
      row.getCell(2).value = kubun;
      row.getCell(3).value = company;
      row.getCell(4).value = prop;
      row.getCell(5).value = site.startTime   || '';
      row.getCell(6).value = site.endTime     || '';
      row.getCell(7).value = site.breakMin    || 0;
      row.getCell(8).value = site.workingTime || '';
      row.getCell(9).value = site.workContent || '';
      if (isMulti) {
        row.getCell(10).value = site.personnelCount || '';
        row.getCell(11).value = site.personnelNames || '';
        row.getCell(12).value = site.highwayFee;
        row.getCell(13).value = site.distance;
        row.getCell(14).value = site.parkingFee;
        row.getCell(15).value = site.materialFee;
      } else {
        row.getCell(10).value = site.highwayFee;
        row.getCell(11).value = site.distance;
        row.getCell(12).value = site.parkingFee;
        row.getCell(13).value = site.materialFee;
      }
      row.commit();
      written = true;
    }

    if (!written) {
      const msg = `既に送信済みの日報です。\n${duplicates.join('\n')}`;
      return [{ json: { valid: false, replyToken: data.replyToken, errorMessage: msg } }];
    }

    const out = await workbook.xlsx.writeBuffer({ useSharedStrings: false });
    const fileName = data.fileName || '稼働表.xlsx';
    const bin = await this.helpers.prepareBinaryData(
      Buffer.from(out), fileName,
      'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet'
    );
    const dupMsg = duplicates.length > 0 ? `\n（重複のためスキップ：${duplicates.join('、')}）` : '';
    return [{ json: { ...data, fileId, valid: true, dupMsg }, binary: { data: bin } }];

  } catch (err) {
    return [{ json: { valid: false, replyToken: data.replyToken, errorMessage: err.message } }];
  }
})();

